function businessDaysBetween(startIso, endIso) {
  const start = new Date(startIso + 'T00:00:00Z');
  const end = new Date(endIso + 'T00:00:00Z');
  let count = 0;
  const cur = new Date(start);
  cur.setUTCDate(cur.getUTCDate() + 1);
  while (cur <= end) {
    const day = cur.getUTCDay();
    if (day !== 0 && day !== 6) count++;
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
  return count;
}

function calendarDaysBetween(startIso, endIso) {
  const start = new Date(startIso + 'T00:00:00Z');
  const end = new Date(endIso + 'T00:00:00Z');
  return Math.round((end - start) / 86400000);
}

const today = $now.toFormat('yyyy-LL-dd');

function classifyOne(item) {
  const { salesforce, clm, netsuite, provisioning, rules, customer_id, playbook_text } = item;

  const issuanceWindowDays = rules.invoicing_policy.issuance_window_business_days;
  const paymentWindowDays = rules.invoicing_policy.payment_window_days;
  const highOverdueThreshold = rules.escalation_policy.high_customer_overdue_days_threshold;

  let issuanceBreach = false;
  if (netsuite.invoice_status === 'not_created') {
    issuanceBreach = businessDaysBetween(clm.signed_date, today) > issuanceWindowDays;
  }

  let paymentBreach = false;
  if (netsuite.invoice_status === 'issued') {
    paymentBreach = calendarDaysBetween(netsuite.issued_date, today) > paymentWindowDays;
  }

  const overdueSteps = provisioning.steps.filter(s => s.status !== 'done' && s.due_date < today);
  const customerOverdue = overdueSteps.filter(s => s.owner === 'customer');
  const csOverdue = overdueSteps.filter(s => s.owner === 'cs');

  const twoOrMoreOverdueWithCustomer = overdueSteps.length >= 2 && customerOverdue.length >= 1;
  const worstCustomerOverdue = customerOverdue.filter(s => calendarDaysBetween(s.due_date, today) > highOverdueThreshold);

  let risk_level = 'low';
  const risks = [];

  if (issuanceBreach) {
    risk_level = 'high';
    risks.push(`invoicing-policy issuance-window breach: invoice not created more than ${issuanceWindowDays} business days after signed_date (${clm.signed_date})`);
  }
  if (twoOrMoreOverdueWithCustomer) {
    risk_level = 'high';
    risks.push(`escalation-policy HIGH: ${overdueSteps.length} overdue provisioning step(s) including customer-owned step(s) (${customerOverdue.map(s => s.name).join(', ')})`);
  }
  if (worstCustomerOverdue.length > 0) {
    risk_level = 'high';
    risks.push(`escalation-policy HIGH: customer-owned step(s) more than ${highOverdueThreshold} days overdue (${worstCustomerOverdue.map(s => s.name).join(', ')})`);
  }

  if (risk_level !== 'high') {
    if (paymentBreach) {
      risk_level = 'medium';
      risks.push(`invoicing-policy payment-window breach: invoice issued ${netsuite.issued_date}, unpaid after ${calendarDaysBetween(netsuite.issued_date, today)} days (> ${paymentWindowDays}-day window)`);
    }
    if (csOverdue.length > 0 && customerOverdue.length === 0) {
      risk_level = 'medium';
      risks.push(`provisioning-checklist: cs-owned overdue step(s) with no customer-owned steps overdue (${csOverdue.map(s => s.name).join(', ')})`);
    }
  }

  let recommended_action = risk_level !== 'low' ? 'notify' : 'none';
  if (customerOverdue.length > 0) {
    recommended_action = 'nudge_customer';
  }

  return {
    customer_id,
    state: { salesforce, clm, netsuite, provisioning },
    playbook_text,
    classification: { risk_level, recommended_action, risks },
    nudge_eligible_steps: customerOverdue,
  };
}

return $input.all().map(inputItem => ({ json: classifyOne(inputItem.json) }));

