const item = $input.first().json;
return [{
  json: {
    customer_id: item.customer_id,
    state: item.state,
    nudge_eligible_steps: item.nudge_eligible_steps,
    verdict: {
      risk_level: item.classification.risk_level,
      recommended_action: item.classification.recommended_action,
      risks: item.classification.risks,
      summary: `${item.customer_id} is LOW risk. No overdue provisioning steps and invoicing is on track. No action needed at this time.`,
      reasoning: `Per escalation-policy.md's LOW condition, nothing is currently overdue and the invoice is within the policy windows defined in invoicing-policy.md.`,
    },
  },
}];

return $input.all().map(inputItem => {
  const item = inputItem.json;
  let customer_id, trigger_source;

  if (item.body && item.body.customer_id) {
    customer_id = item.body.customer_id;
    trigger_source = `webhook:${item.body.event || 'unknown'}`;
  } else if (item.customer_id) {
    customer_id = item.customer_id;
    trigger_source = 'schedule';
  } else {
    throw new Error('Unable to determine customer_id from trigger data: ' + JSON.stringify(item));
  }

  return { json: { customer_id, trigger_source } };
});
